parameters.jsCode:
const body = ($input.first().json.body || {});
const token = (body.agent_token || '').trim();
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const query = uuidRe.test(token)
  ? `SELECT id, business_name FROM clients WHERE token = '${token}' AND status = 'active' LIMIT 1`
  : `SELECT null::uuid AS id, null::text AS business_name WHERE false`;
return [{ json: { client_query: query } }];
